REPLACE INTO `sms_templates` (`id`, `campaign`, `name`, `template`, `created_at`, `updated_at`) VALUES (1,'satisfaction','Relance note basse','Bonjour {prenom}, ici Raphael. J ai bien pris connaissance de votre note sur la plateforme. Je cherche a m ameliorer et votre avis est essentiel.                   \n\n\nPourriez vous m accorder deux min pr que je puisse comprendre ce qui n a pas ete et vous montrer ma volonte de corriger le tir ? merci cdt','2025-06-13 09:32:31','2025-06-17 10:27:02'),(2,'satisfaction','Relance note injustifiée','Bonjour {prenom}, ici Raphael. Je vous remercie encore pour votre séjour chez nous et pour avoir pris le temps de laisser un commentaire.\r\n\r\nJ ai vu votre aimable commentaire et je vous en remercie. J ai aussi remarqué la note de [7 ou 8]/10 qui l\'accompagne. Pour moi, qui vise une expérience 10/10 pour chaque voyageur, cette note est l\'occasion d\'apprendre.\r\n\r\nJe me permets donc de vous solliciter : y a-t-il un petit détail, meme minime, qui nous aurait empêché d atteindre la note parfaite à vos yeux ?\r\n\r\nAucune obligation de répondre bien sûr, mais votre perspective nous serait extrêmement utile.\r\nExcellente journée à vous.','2025-06-13 09:32:31','2025-06-13 11:11:36'),(3,'accueil','accueil','Bonjour {prenom},\n\nJ’espère que votre arrivée s’est bien déroulée et que vous vous sentez déjà chez vous ?!\n\nN’hésitez pas à me dire si tout est à votre convenance ou si vous avez la moindre question ou besoin d’assistance.\n\nJe reste joignable au +33647554678.\n\nTrès bonne journée et profitez bien du logement !\nRaphaël – Frenchy Conciergerie','2025-06-13 09:32:31','2025-06-23 06:38:42'),(4,'accueil','checkout','Bonjour {prenom}!\nVotre séjour touche bientôt à sa fin. Si vous avez une idée de l\'heure de votre départ du logement merci de me la communiquer ?.\nDans la mesure du possible, merci de :\n– sortir les poubelles,\n– défaire le lit,\n– faire la vaisselle\nJe m’occupe du reste !\nJ’espère que vous avez passé un agréable moment, et peut-être à très bientôt dans l’un de mes logements !\nRaphaël – Frenchy Conciergerie','2025-06-18 02:57:32','2025-06-23 06:40:37'),(5,'accueil','preparation','Bonjour {prenom},\n\nDans 4 jours, vous arriverez au sein de notre logement. Pour que votre séjour soit parfait dès votre arrivée, n’hésitez pas à me faire part de vos préférences : heure d’arrivée, matériel bébé, recommandations de restaurants, etc.\n\nJe reste à votre disposition pour répondre à toutes vos questions.\n\nÀ très bientôt !\nRaphaël au +33647554678\nFrenchy Conciergerie','2025-06-18 02:57:32','2025-06-23 06:40:40');
